    toc: false
---




::: {.cell}
<style type="text/css">
:root {
  --primary-green: #1DB584;
  --secondary-blue: #4A90E2;
  --accent-purple: #7B68EE;
  --light-gray: #F5F5F5;
  --dark-text: #333333;
  --border-gray: #CCCCCC;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  background-color: var(--light-gray);
  color: var(--dark-text);
  line-height: 1.6;
}

.hero-section {
  background: linear-gradient(135deg, var(--primary-green) 0%, var(--secondary-blue) 100%);
  color: white;
  padding: 60px 40px;
  text-align: center;
  margin-bottom: 50px;
}

.hero-section h1 {
  font-size: 2.5em;
  margin-bottom: 20px;
  font-weight: 700;
  letter-spacing: 0.5px;
}

.hero-section p {
  font-size: 1.1em;
  max-width: 800px;
  margin: 0 auto;
  line-height: 1.8;
  opacity: 0.98;
}

.message-box {
  padding: 15px 20px;
  margin-bottom: 30px;
  border-radius: 4px;
  border-left: 5px solid var(--primary-green);
  background-color: #EAFAF3;
  color: #1a6643;
  display: none;
}

.message-box.success {
  border-left-color: var(--primary-green);
  background-color: #EAFAF3;
  color: #1a6643;
  display: block;
}

.message-box.error {
  border-left-color: #DC3545;
  background-color: #F8D7DA;
  color: #721C24;
  display: block;
}

.section-box {
  background: white;
  margin-bottom: 40px;
  border-radius: 6px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  padding: 40px;
}

.section-title {
  font-size: 1.8em;
  font-weight: 700;
  color: var(--primary-green);
  margin-bottom: 10px;
  padding-bottom: 15px;
  border-bottom: 3px solid var(--secondary-blue);
}

.section-description {
  color: #666;
  font-size: 0.95em;
  margin-bottom: 30px;
  padding: 15px;
  background-color: var(--light-gray);
  border-radius: 4px;
  border-left: 4px solid var(--secondary-blue);
}

.form-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 25px;
  margin-bottom: 30px;
}

.form-grid.full {
  grid-template-columns: 1fr;
}

.form-group {
  display: flex;
  flex-direction: column;
}

.form-group label {
  font-weight: 600;
  margin-bottom: 8px;
  font-size: 0.95em;
  color: var(--dark-text);
}

.form-group label .required {
  color: #DC3545;
  margin-left: 3px;
}

.form-group input,
.form-group select,
.form-group textarea {
  padding: 12px 14px;
  border: 2px solid var(--border-gray);
  border-radius: 4px;
  font-size: 1em;
  font-family: inherit;
  background-color: white;
  color: var(--dark-text);
  transition: all 0.3s ease;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
  outline: none;
  border-color: var(--primary-green);
  box-shadow: 0 0 8px rgba(29, 181, 132, 0.2);
}

.form-group textarea {
  resize: vertical;
  min-height: 80px;
}

.table-wrapper {
  overflow-x: auto;
  margin-top: 30px;
}

.item-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.95em;
}

.item-table thead {
  background-color: var(--primary-green);
  color: white;
  position: sticky;
  top: 0;
  z-index: 10;
}

.item-table thead th {
  padding: 15px 12px;
  text-align: left;
  font-weight: 600;
  border: 1px solid #999;
}

.item-table tbody tr {
  border-bottom: 1px solid #ddd;
}

.item-table tbody tr:nth-child(even) {
  background-color: #FAFAFA;
}

.item-table tbody tr:hover {
  background-color: #F0F8F5;
}

.item-table td {
  padding: 12px;
  border: 1px solid #ddd;
}

.item-table .rating-select {
  width: 70px;
  padding: 8px;
  border: 1px solid var(--border-gray);
  border-radius: 3px;
  font-size: 0.9em;
}

.item-table .comment-textarea {
  width: 100%;
  padding: 8px;
  border: 1px solid var(--border-gray);
  border-radius: 3px;
  font-size: 0.85em;
  min-height: 60px;
  font-family: inherit;
  resize: vertical;
}

.button-container {
  display: flex;
  gap: 15px;
  justify-content: center;
  margin-top: 50px;
  flex-wrap: wrap;
}

.btn {
  padding: 14px 40px;
  border: none;
  border-radius: 4px;
  font-size: 1em;
  font-weight: 600;
  cursor: pointer;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  transition: all 0.3s ease;
}

.btn-primary {
  background-color: var(--primary-green);
  color: white;
}

.btn-primary:hover {
  background-color: #169D6E;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(29, 181, 132, 0.3);
}

.btn-secondary {
  background-color: var(--secondary-blue);
  color: white;
}

.btn-secondary:hover {
  background-color: #3A7BC8;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(74, 144, 226, 0.3);
}

.loading {
  display: none;
  text-align: center;
  padding: 20px;
}

.spinner {
  border: 4px solid var(--light-gray);
  border-top: 4px solid var(--primary-green);
  border-radius: 50%;
  width: 40px;
  height: 40px;
  animation: spin 1s linear infinite;
  margin: 0 auto 15px;
}

@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

@media (max-width: 768px) {
  .form-grid {
    grid-template-columns: 1fr;
  }

  .section-box {
    padding: 20px;
  }

  .hero-section {
    padding: 40px 20px;
  }

  .hero-section h1 {
    font-size: 2em;
  }

  .item-table {
    font-size: 0.85em;
  }

  .item-table td {
    padding: 8px;
  }

  .item-table .rating-select,
  .item-table .comment-textarea {
    font-size: 0.8em;
  }
}
</style>
:::


<div class="hero-section">
  <h1>Expert Content Review</h1>
  <p>
    Dear Researcher and Expert Reviewer,
    <br><br>
    Thank you for contributing your expertise to the ASQ-3 Saudi Arabic validation study. 
    Your rigorous evaluation of each item is essential for ensuring that this developmental screening 
    measure is culturally appropriate, linguistically sound, and psychometrically reliable for use in 
    the Saudi Arabian context. Please complete the form below by rating each item on quality and clarity, 
    and providing any clinical observations that may be relevant for implementation.
  </p>
